  const decreaseFontSize = () => setFontSize(s => Math.max(s - 2, 12));

  const fontStyles = {
    arabic: { fontSize: `${fontSize * 1.75}px`, lineHeight: `${fontSize * 2.8}px` },
    translation: { fontSize: `${fontSize}px` },
    transliteration: { fontSize: `${fontSize-2}px`}
  };

  const SurahHeader = () => (
